import React, { useState } from "react";

//expandable with a list https://hlstore.ru/catalog/
const ExpandableItem = ({ title, contentArr }) => {
  console.log(contentArr);
  const [expanded, setExpanded] = useState(false);

  const handleToggle = () => {
    setExpanded(!expanded);
  };

  return (
    <div className={`expandable-element ${expanded ? "expanded" : ""}`}>
      <div onClick={handleToggle}>
        <h3 className="expandable_h3">{title}</h3>
      </div>
      {expanded &&
        contentArr.map(({ item }) => {
          <p className="expandable_p">{`Item: ${item}`}</p>;
        })}
    </div>
  );
};

function ShopMain() {
  return (
    <>
      <h1 className="sub-header">Каталог товаров</h1>
      <div className="catalogue">
        <div className="list">
          <div className="catalogue-list-expandable">
            <ExpandableItem
              title="Всё для татуировки"
              contentArr={["1", "1"]}
            />
          </div>
          <div className="catalogue-list-expandable">
            <ExpandableItem title="Всё для пирсинга" contentArr="" />
          </div>
        </div>
        <div className="filter-options"></div>
        <div className="goods"></div>
      </div>
    </>
  );
}

export default ShopMain;
